import random, time, anthropic

client = anthropic.Anthropic(max_retries=0)  # disable SDK retries

def call_with_backoff(prompt, max_attempts=4):
    base = 0.5  # 500 ms initial
    max_delay = 8.0

    for attempt in range(max_attempts):
        try:
            return client.messages.create(
                model="claude-sonnet-4-6",
                max_tokens=1024,
                messages=[{"role": "user", "content": prompt}],
            )
        except anthropic.RateLimitError as e:
            retry_after = getattr(e, "retry_after", None)
            if retry_after:
                time.sleep(retry_after)  # Honor Retry-After
            else:
                delay = min(base * (2 ** attempt), max_delay)
                wait = random.uniform(0, delay)  # full jitter
                time.sleep(wait)
        except anthropic.InternalServerError:
            delay = min(base * (2 ** attempt), max_delay)
            time.sleep(delay)
        except anthropic.APIConnectionError:
            delay = min(base * (2 ** attempt), max_delay)
            time.sleep(delay)
        else:
            break  # Non-retryable error

    raise RuntimeError("Max retry attempts reached")

except anthropic.RateLimitError as e:
    retry_after = getattr(e, "retry_after", None)
    if retry_after:
        time.sleep(retry_after)  # Server says "wait 10s" — do it
    else:
        # Fallback to exponential backoff
        delay = min(base * (2 ** attempt), max_delay)
        time.sleep(random.uniform(0, delay))

