import time
from collections import deque

class CircuitBreaker:
    def __init__(self, failure_threshold=5, recovery_timeout=30):
        self.failure_threshold = failure_threshold
        self.recovery_timeout = recovery_timeout
        self.failures = deque()
        self.last_failure_time = None
        self.is_open = False

    def record_failure(self):
        self.failures.append(time.time())
        self.last_failure_time = time.time()

        if len(self.failures) >= self.failure_threshold:
            self.is_open = True  # Open circuit — block requests
            print("Circuit breaker OPEN — blocking requests")

    def record_success(self):
        if self.is_open:
            if time.time() - self.last_failure_time >= self.recovery_timeout:
                self.is_open = False  # Close circuit — resume requests
                self.failures.clear()
                print("Circuit breaker CLOSED — resuming requests")

    def can_proceed(self):
        if not self.is_open:
            return True

        if time.time() - self.last_failure_time >= self.recovery_timeout:
            self.is_open = False
            self.failures.clear()
            return True

        return False

# Usage
circuit = CircuitBreaker(failure_threshold=5, recovery_timeout=30)

