import anthropic, time, random

client = anthropic.Anthropic(max_retries=0)  # We handle retries

def call_claude(prompt, max_attempts=3, timeout_budget=8.0):
    """Production retry policy for Claude API."""

    base_delay = 0.5
    max_delay = 4.0
    start = time.time()

    for attempt in range(max_attempts):
        # 1. Time budget check
        if time.time() - start > timeout_budget:
            raise TimeoutError("Retry budget exceeded")

        try:
            return client.messages.create(
                model="claude-sonnet-4-6",
                max_tokens=1024,
                messages=[{"role": "user", "content": prompt}],
            )

        # 2. Retryable errors
        except anthropic.RateLimitError as e:
            # Honor Retry-After header first
            retry_after = getattr(e, "retry_after", None)
            if retry_after:
                time.sleep(retry_after)
            else:
                delay = min(base_delay * (2 ** attempt), max_delay)
                time.sleep(random.uniform(0, delay))  # jitter

        except anthropic.InternalServerError:
            delay = min(base_delay * (2 ** attempt), max_delay)
            time.sleep(delay)

        except anthropic.APIConnectionError:
            delay = min(base_delay * (2 ** attempt), max_delay)
            time.sleep(delay)

        # 3. Non-retryable errors — fail immediately
        except anthropic.BadRequestError:
            raise  # Fix the request, don't retry

        except anthropic.AuthenticationError:
            raise  # Fix credentials, don't retry

        except anthropic.PermissionDeniedError:
            raise  # Fix permissions, don't retry

        except anthropic.NotFoundError:
            raise  # Fix model name, don't retry

    # 4. Exhausted retry budget
    raise RuntimeError("Max retry attempts reached")
